mapper.select:
SELECT

FROM reve_property_info t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.source_id = #{request.sourceId}


    AND t0.bill_type = #{request.billType}


    AND t0.do_id = #{request.doId}


    AND t0.do_type = #{request.doType}


    AND t0.security_way = #{request.securityWay}


    AND t0.security_type = #{request.securityType}


    AND t0.reve_name = #{request.reveName}


    AND t0.reve_measure LIKE CONCAT('%',#{request.reveMeasure},'%')


    AND t0.is_dispose = #{request.isDispose}


    AND t0.dispose_money = #{request.disposeMoney}


    AND t0.preserve_date = #{request.preserveDate}


    AND t0.remark = #{request.remark}


    AND t0.debt_repayment_date = #{request.debtRepaymentDate}


    AND t0.debt_repayment_money = #{request.debtRepaymentMoney}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
